 30→func TestUploadHandler_NoAuth(t *testing.T) {
 31→	handler := uploadHandler(nil, 50<<20)
 32→
 33→	req := httptest.NewRequest(http.MethodPost, "/upload", nil)
 34→	rr := httptest.NewRecorder()
 35→	handler.ServeHTTP(rr, req)
 36→
 37→	// Without storage, returns 503 before checking auth
 38→	// The auth middleware handles 401 before this handler is called,
 39→	// but we still guard against nil claims
 40→	if rr.Code != http.StatusServiceUnavailable {
 41→		t.Errorf("expected 503 (nil storage checked first), got %d", rr.Code)
 42→	}
 43→}
