 53→func TestMimeFromFilename(t *testing.T) {
 54→	tests := []struct {
 55→		name     string
 56→		filename string
 57→		want     string
 58→	}{
 59→		{"mp3", "audio.mp3", "audio/mpeg"},
 60→		{"wav", "recording.wav", "audio/wav"},
 61→		{"ogg", "file.ogg", "audio/ogg"},
 62→		{"webm", "capture.webm", "audio/webm"},
 63→		{"m4a", "voice.m4a", "audio/mp4"},
 64→		{"flac", "lossless.flac", "audio/flac"},
 65→		{"unknown", "file.txt", ""},
 66→		{"no extension", "noext", ""},
 67→		{"uppercase", "FILE.MP3", "audio/mpeg"},
 68→	}
 69→
 70→	for _, tt := range tests {
 71→		t.Run(tt.name, func(t *testing.T) {
 72→			got := mimeFromFilename(tt.filename)
 73→			if got != tt.want {
 74→				t.Errorf("mimeFromFilename(%q) = %q, want %q", tt.filename, got, tt.want)
 75→			}
 76→		})
 77→	}
 78→}
