129→func TestUploadResponse_JSON(t *testing.T) {
130→	resp := uploadResponse{
131→		Key:         "user123/uploads/abc.wav",
132→		ContentType: "audio/wav",
133→		Size:        12345,
134→	}
135→
136→	data, err := json.Marshal(resp)
137→	if err != nil {
138→		t.Fatalf("marshal: %v", err)
139→	}
140→
141→	var decoded uploadResponse
142→	if err := json.Unmarshal(data, &decoded); err != nil {
143→		t.Fatalf("unmarshal: %v", err)
144→	}
145→
146→	if decoded.Key != resp.Key {
147→		t.Errorf("key: got %q, want %q", decoded.Key, resp.Key)
148→	}
149→	if decoded.ContentType != resp.ContentType {
150→		t.Errorf("content_type: got %q, want %q", decoded.ContentType, resp.ContentType)
151→	}
152→	if decoded.Size != resp.Size {
153→		t.Errorf("size: got %d, want %d", decoded.Size, resp.Size)
154→	}
155→}
